create table dirkspzm32.ems_artikel (
    sid               varchar2(2 char) default '01' not null enable,
    firma_nr          number default 1 not null enable,
    ems_art_name      varchar2(20 char) not null enable,
    erz_login_id      number(*, 0) not null enable,
    erz_datum         date not null enable,
    aend_login_id     number(*, 0),
    aend_datum        date,
    ems_art_text      varchar2(50 char),
    ems_art_gruppe_id number(*, 0),
    aktiv             varchar2(10 char) default 'T' not null enable,
    beschreibung      varchar2(255 char),
    mengen_einheit    varchar2(10 char) default 'STK' not null enable,
    gewicht_kg        number(*, 3) default 0 not null enable,
    foto_datei_k      varchar2(255 char),
    foto_datei_n      varchar2(255 char),
    artikel_id        number(*, 0),
    lte_name          varchar2(22 char),
    lhm_name          varchar2(50 char)
);

alter table dirkspzm32.ems_artikel
    add constraint pk_ems_artikel primary key ( ems_art_name )
        using index enable;


